    // margin-block-end: 2rem;
    border-radius: 0.5rem;
    border: 0;

    .card-header-title {
        font-weight: 500;
        font-size: 1rem;
        color: var(--text-800);
        border-top-left-radius: 0.5rem;
        border-top-right-radius: 0.5rem;
        margin: -1.5rem -2rem 1rem;
        padding: 0.75rem 2rem;
        display: flex;
        align-items: center;
        gap: 0.75rem;

        .icon {
            i {
                font-size: 1.125rem;
            }
        }

        &.lightblue {
            background-color: var(--bg-blue);
        }

        &.lightgreen {
            background-color: var(--bg-green);
        }

        &.lightred {
            background-color: var(--bg-red);
        }

        &.lightteal {
            background-color: var(--bg-teal);
        }
        &.lightindigo {
            background-color: var(--bg-indigo);
        }
        &.lightorange {
            background-color: var(--bg-orange);
        }
    }

    .card-body-content {
        .p-links+.p-links {
            border-top: 1px solid var(--text-300-10);
            padding-top: 0.75rem;
        }

        .p-links:not(:last-child) {
            padding-bottom: 0.75rem;
        }

        .p-links {
            color: var(--text-500);
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: space-between;
            overflow: hidden;
            transition: color 0.4s ease;

            .link-holder {
                display: flex;
                align-items: center;
                gap: 0.5rem;
            }
            .icon {
                opacity: 0;
                transform: translateX(100%);
                transition: transform 0.4s ease, opacity 0.4s ease;
                font-size: 1.25rem;
            }

            &:hover {
                color: var(--blue);
                .icon {
                    transform: translateX(0);
                    opacity: 1;
                }

            }
        }
    }

    // &.module-card {
    //     max-height: 284px;
    // }
}

// ** Horizontal Cards **//

.hr-card {
    @apply border border-slate-200 p-5 bg-white rounded-lg relative  cursor-pointer font-medium text-slate-600;
    transition: all 0.3s ease;

    &:not(:last-child) {
        @apply mb-4;
    }


   &.arrow {
        &:hover {
            @apply bg-blue-50 text-blue-500;

            &::after {
                content: '\f061';
                font-family: 'Font Awesome 6 Pro';
                @apply absolute top-1/2 right-8 font-bold;
                transform: translate(0, -50%);
            }
        }
   }

}

.hr-card-2{
    @apply border border-slate-200  bg-white rounded-lg relative font-medium text-slate-600 flex;

    .hr-card-number {
        @apply  p-4 flex items-center justify-center cursor-pointer;
    }

    .hr-card-text {
        @apply p-4 flex-1;
    }


}

// --------------------------------
// Daisy UI Form
// --------------------------------

.input-bordered {
    border-color: hsl(215 28% 17% / 0.2);
}

.form-flex {
    @apply flex flex-row items-center justify-start gap-7;

     &-alt { 
        @apply justify-between; 

        .btn-wrapper { 
            @apply mt-0;
        }
    }

    &-end {
        @apply items-end
    }
}

.form-grid {
    @apply grid grid-cols-2 gap-7 items-center;

    &-one {
        @apply grid grid-cols-1;
    }

     &-alt { 
        @apply grid-cols-3 items-center;
    }
}


.form-label {
    @apply text-base text-slate-500 cursor-pointer; 

    &.required { 
        &::after {
            content: "*";
            @apply text-red-600 ml-1;
        }
    }
}


.form-text {
    @apply mt-2;
}

.form-control-holder {
    @apply mt-2;
}

.form-control {
    @apply input input-bordered w-full;

     &-alt { 
        @apply w-1/2 ml-auto;
    }
    &-error { 
        @apply input-error;
    }
}

.error-text { 
    @apply text-[13px] text-red-600 mt-1;
}


.file-control {
    --n: theme('colors.secondary');
    --nc: 0 0% 100%;
      @apply file-input input-bordered w-full;
    }

.form-helper {
    @apply mt-2 text-sm text-slate-400;
}


// *******  Radio  ******* //

.form-check {
    @apply mt-2 flex gap-4 flex-row items-center;
}

.form-check-label {
    @apply label flex flex-row items-center cursor-pointer justify-start;

    .radio {
        @apply me-2 checked:bg-blue-600;
    }
}

// *******  Radio + Grid Data ******* //

.form-box {
    @apply relative z-10 px-8 py-5 grid grid-cols-[60px_repeat(2,_minmax(0,_1fr))] gap-x-5 gap-y-1 [&_input]:row-span-2 items-center cursor-pointer;

    input {
        @apply checked:bg-blue-600;
        + span::before {
            content: '';
            @apply absolute top-0 bottom-0 left-0 right-0 -z-10 rounded-lg bg-white shadow-xl;
        }
    }

    span {
        @apply text-slate-500;
    }

    strong {
        @apply text-slate-700;
    }

    input:checked + span::before {
        box-shadow: inset 0 0 0 3px rgba(37 99 235 / 20%);
    }
}


// --------------------------------
// FormKit Form CSS START
// --------------------------------

.fk-group {
    @apply relative;
}


// *******  FormKit Error Message ******* //
.fk-messages {
    .fk-message {@apply mt-1 text-sm;
        &-error {@apply text-red-600;}
    }
}


// *******  Radio + Checkbox Labels & Options ******* //

.fk-options-group {
    @apply flex items-center gap-4;
}

.fk-option {
    @apply mt-2;
}

.fk-main-label {
    @apply text-base text-slate-500;
}

.fk-label-text {
    @apply label-text ml-2 ;
}


// *******  Radio SCSS START ******* //

.fk-group[data-type="radio"] {

    .fk-decorator {
        @apply  w-6 h-6 p-2 block rounded-full cursor-pointer border;
        border-color: hsl(var(--bc) / var(--tw-border-opacity));
        --tw-border-opacity: 0.2;

        svg {
            @apply scale-0 transition-transform;

            circle {
                @apply fill-blue-600; 
            }
        }
    }

    // Disable radio 

    .fk-option[data-disabled="true"] {
        opacity: 60%;
    }

    // When Radio Is Checked

    [data-checked]  {
        @apply fill-blue-600; 

        .fk-decorator {
            box-shadow: inset 0 0 0 1px #2563eb;
        }

        svg {
            @apply w-full scale-[2] ;

            circle {
                @apply fill-blue-600; 
            }
        }
    }
}
// *******  Radio SCSS END ******* //


// *******  Checkbox SCSS START ******* //

.fk-group[data-type="checkbox"] {

    .fk-decorator {
        @apply  w-6 h-6 block cursor-pointer border rounded-lg bg-white;
        border-color: hsl(var(--bc) / var(--tw-border-opacity));
        --tw-border-opacity: 0.2;

        &:hover {
            border-color: #2563eb;
        }

        .fk-decorator-icon {
            svg {
                display: none;
            }
        }
    }

    // When Checkbox Is Checked

    [data-checked]  {
        @apply fill-blue-600; 

        .fk-decorator {
            @apply bg-blue-600;

            .fk-decorator-icon {
                &::after {
                    content: '\f00c';
                    font-family: 'Font Awesome 6 Pro';
                    color: #fff;
                    position: absolute;
                    top: 0;
                    left: 0;
                    right: 0;
                    bottom: 0;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                }
            }
        }
    }

}

// *******  Checkbox SCSS END ******* //

// *******  INPUT SCSS START ******* //

.fk-group[data-family="text"] {

    .fk-wrapper {
        @apply w-full;

        .fk-main-label {
            @apply mb-2 inline-block;
        }
    }

    .fk-inner {
        @apply relative;
    }

    .fk-text-input {
        @apply form-control;
    }

    .formkit-suffix-icon {
        position: absolute;
        right: 8px;
        top: 50%;
        transform: translate(-50%, -50%);

        svg {
            width: 1rem;
        }
    }
}

// If Invalid Response 

.fk-group[data-family="text"][data-invalid="true"] {

    .fk-text-input {
        @apply input-error;
    }
}


// *******  INPUT SCSS END ******* //


// *******  INPUT Password SCSS START ******* //
.fk-group[data-type="password"] {

    .fk-inner {
        @apply relative;
    }

    .formkit-suffix-icon {
        position: absolute;
        right: 8px;
        top: 50%;
        transform: translate(-50%, -50%);

        svg {
            width: 1rem;
        }
    }
}
// *******  INPUT Password SCSS END ******* //

// *******  INPUT Single File SCSS START ******* //

.fk-group[data-type="file"] {

    .fk-inner {
        @apply relative;

        .fk-file-input {
            @apply file-control mt-2;
            padding-right: 2.5rem
        }

        .fk-file-nofile {
            @apply hidden;
        }

        .fk-file-list-container {
            @apply border rounded-lg p-4;

            .fk-file-list {
                @apply truncate;

            }

            .fk-file-icon  {
                &::after {
                    content: '\f15b';
                    font-family: 'Font Awesome 6 Pro';
                    margin-right: 0.5rem;
                }
            }

            .fk-file-icon {
                svg {
                    @apply hidden;
                }
            }

            .fk-file-name {
                @apply text-sm font-medium;
            }

            .fk-file-removeall {
                @apply block text-xs mt-2 text-blue-600 hover:text-red-600;
            }

            .fk-file-single-remove-icon {
                @apply w-4 h-4;
                position: absolute;
                top: 22%;
                right: 1rem;
                transform: translate(0, -50%);
            }
        }

    }

}

// *******  INPUT Single File SCSS END ******* //



// *******  INPUT Multiple File SCSS START ******* //
.fk-group[data-multiple="true"] {

    .fk-file-removeall {
        @apply text-xs  text-blue-600 hover:text-red-600;
    }
}
// *******  INPUT Multiple File SCSS END ******* //




// *******  Select SCSS START ******* //

.fk-group[data-type="select"] {

    .fk-inner {
        @apply flex items-end gap-4;
    }

    .fk-select-input {
        @apply select select-bordered w-full mt-2 font-normal;
        border-color: hsl(var(--bc) / var(--tw-border-opacity));
        --tw-border-opacity: 0.2;
    }

    .fk-select-icon {
        display: none;
    }
}

// *******  Select SCSS END ******* //


// *******  Textarea SCSS START ******* //

.fk-group[data-type="textarea"] {

    @apply w-full;
    .fk-textarea-input {
        @apply textarea textarea-bordered w-full mt-2;
        border-color: hsl(var(--bc) / var(--tw-border-opacity));
        --tw-border-opacity: 0.2;
    }

}

// *******  Textarea SCSS END ******* //


.required { 
    .fk-main-label {
        &::after {
            content: "*";
            @apply text-red-600 ml-1;
        }
    }
}

