// *******  ILike Page Start ******* //

.ilike {
  background-image: linear-gradient(to right, rgba(0, 0, 0, 0.1)),
    url("/assets/images/ilike-background.jpg");
  background-size: cover;
  height: calc(100vh - 166px);
  background-position: top;
}

.ilike-card {
  @apply relative cursor-pointer font-bold text-slate-600;

  .ic-sem {
    @apply text-lg relative z-20;
  }

  &:hover {
    // color: #8b0a5b;
    color: #54519e;
  }

  &:hover::after {
    content: "";
    background-image: url("/assets/images/pattern.svg");
    width: 80px;
    height: 80px;
    position: absolute;
    top: 50%;
    left: 15%;
    transform: translate(0, -50%);
    opacity: 0.3;
    @apply transition-all;
  }

  &:hover::before {
    content: "\f0a9";
    font-family: "Font Awesome 6 Pro";
    font-size: 1.5rem;
    position: absolute;
    top: 50%;
    right: 10%;
    opacity: 0.9;
    transform: translate(0, -50%);
    // color: #8b0a5b;
    color: hsl(242, 32%, 47%);
    transition: 0.5s ease-in;
  }
}


