      width: 100%;
      height: 3rem;
      border: 1px solid rgba(31, 41, 55, 0.2);
      border-radius: 0.5rem;
      padding: 0 1rem;

      &:hover {
        outline: 2px solid rgba(31, 41, 55, 0.2);
        outline-offset: 2px;
      }

      &:focus-visible {
        border: 1px solid rgba(31, 41, 55, 0.2);
      }
    }

