:root {
    --table-header-color: #475569;
    --table-header-fontSize: 0.875rem;
    --table-header-fontWeight: 600;
    --table-header-backgroundColor: #e2e8f0;
    --table-header-padding-inline: 0.75rem;
    --table-header-padding-block: 0.5rem;
    --table-border-color: #cbd5e1;
    --table-data-fontSize: 0.875rem;
    --table-active-row-background: #94a3b8;
    --table-hover-background: #f1f5f9;
    --table-zebra-pattern-background:#94a3b8;
    --table-height-for-fixed-header: 350px;
    --table-width-for-fixed-cols: 992px;
}

.table {
    border: 1px solid var(--table-border-color);
    & :where(thead, tfoot) {
        font-size: var(--table-header-fontSize);
        font-weight: var(--table-header-fontWeight);
        color: var(--table-header-color);
        background-color: var(--table-header-backgroundColor);
    }

    thead {
        th {
            padding-inline: var(--table-header-padding-inline);
            padding-block: var(--table-header-padding-block);
            text-align: center;
            border-right: 1px solid var(--table-border-color);
        }
    }

    tbody {
        tr {
            border-bottom: 1px solid var(--table-border-color);
            transition: hover 0.15s theme('cubicBezier.val') ease-out;
            &:hover {
                background-color: var(--table-hover-background);
            }
        }

        td {
            @apply align-middle;
            padding-inline: var(--table-header-padding-inline);
            padding-block: var(--table-header-padding-block);
            font-size: var(--table-data-fontSize);
            color: var(--table-header-color);

            +td {
                border-left: 1px solid var(--table-border-color);
            }

            .radio {
                @apply align-middle;
            }
        }
    }
}


.custom-datatable {
    table {
        position: relative;
        text-align: left;
        border: 1px solid var(--table-border-color);
        width: 100%;

        & :where(thead, tfoot) {
            font-size: var(--table-header-fontSize);
            font-weight: var(--table-header-fontWeight);
            color: var(--table-header-color);
            background-color: var(--table-header-backgroundColor);
        }

        thead {
            th {
                padding-inline: var(--table-header-padding-inline);
                padding-block: var(--table-header-padding-block);
                text-align: center;
                border-right: 1px solid var(--table-border-color);
            }

            .p-column-title {
                margin: 0;
            }

            .p-column-header-content {
                @apply gap-1;

                .p-checkbox {
                    order: -1;
                }
            }
        }

        tbody {
            tr {
                border-bottom: 1px solid var(--table-border-color);
                transition: hover 0.15s theme('cubicBezier.val') ease-out;
                &:hover {
                    background-color: var(--table-hover-background);
                }
            }

            td {
                @apply align-middle;
                padding-inline: var(--table-header-padding-inline);
                padding-block: var(--table-header-padding-block);
                font-size: var(--table-data-fontSize);
                color: var(--table-header-color);

                +td {
                    border-left: 1px solid var(--table-border-color);
                }

                &.p-selection-column {
                    @apply text-center;
                }

                // Formkit Checkbox Center align for table

                .formkit-wrapper {
                    @apply justify-center;
                }
            }
        }
    }

    &.pin-rows {
        table {
            thead {
                tr {
                    position: sticky;
                    top: 0;
                    z-index: 10;
                    background-color: var(--table-header-background);
                }
            }
        }
    }

    &.pin-cols {
        table {
            tbody {
                tr {
                    td:first-child {
                        position: sticky;
                        left: 0;
                        right: 0;
                        z-index: 10;
                        background-color: var(--table-header-background);
                    }
                }
            }
        }
    }

    .table-empty-state {
        @apply text-center p-6 text-2xl text-slate-400 font-bold;
        p {
            @apply mb-4 max-w-sm m-auto;
        }
    }

}   


