.custom-vueTree {
    .ct-child {
        @apply p-4 flex items-center gap-2 hover:bg-blue-50;
    }

    .folder_icon, .folder_icon_active {
        @apply hidden;
    }

    input[type=checkbox] {
        @apply checkbox;
    }

    ul {

        li {
            &:not(:last-child) {
                @apply border-l border-dashed border-l-slate-700;
            }

            .ct-child {

                &::before {
                    content: "";
                    position: relative;
                    left: -16px;
                    top: 50%;
                    transform: translate(0, -50%);
                    height: 16px;
                    width: 24px;
                    display: inline-block;
                    @apply border-b border-dashed border-b-slate-700;

                }

            }

            &:last-child {
               > .ct-child {
                    &::before {
                        content: "";
                        display: inline-block;
                        border-left: 1px dashed #000;
                    }
                }
            }


        }
    }

    // .ct-text {
    //     @apply font-normal;
    // }
}

