export const mutations = {
  [types.MUTATE_SET_CURRENT_ACADEMICYEAR]: (state) => {
    state.status = 'loading'
  },
  [types.MUTATE_ACADEMICYEAR_SAVE_OBJ]: (state, academicYearData) => {
    state.currentAcademicYear = Encryption(academicYearData)

    state.status = 'success'
  },
  [types.MUTATE_ACADEMICYEAR_ERROR]: (state) => {
    state.status = 'error'
  },
  // For Next Academic Year
  [types.MUTATE_SET_NEXT_ACADEMICYEAR]: (state) => {
    state.status = 'loading'
  },
  [types.MUTATE_NEXT_ACADEMICYEAR_SAVE_OBJ]: (state, academicYearData) => {
    state.nextAcademicYear = Encryption(academicYearData)
    state.status = 'success'
  },
  [types.MUTATE_NEXT_ACADEMICYEAR_ERROR]: (state) => {
    state.status = 'error'
  },
  // For Finance Year
  [types.MUTATE_SET_CURRENT_FINANCEYEAR]: (state) => {
    state.finYearStatus = 'loading'
  },
  [types.MUTATE_FINANCEYEAR_SAVE_OBJ]: (state, financeYearData) => {
    state.currentFinancialYear = Encryption(financeYearData)
    state.finYearStatus = 'success'
  },
  [types.MUTATE_FINANCEYEAR_ERROR]: (state) => {
    state.finYearStatus = 'error'
  },
  [types.MUTATE_MENU_SAVE_OBJ]: (state, menuData) => {
    state.menu = Encryption(menuData)
    state.menuStatus = 'success'
  },
  [types.MUTATE_RESET_MENU]: state => {
    state.menu = ''
    state.menuStatus = 'pending'
  }

}

